/**
 * Contacts table in Supabase (`contacts`).
 *
 * Expected columns: id, name (text), owner (text/email), notes (text, optional), private_notes (text, optional)
 *
 * SQL (run in Supabase if missing):
 *
 *   create table if not exists public.contacts (
 *     id    bigint generated by default as identity primary key,
 *     name  text not null,
 *     owner text not null,
 *     private_notes text,
 *     notes text
 *   );
 *   -- alter table public.contacts add column if not exists notes text;
 */

let client = null;

function isConfigured() {
  return !!(process.env.SUPABASE_URL && process.env.SUPABASE_SERVICE_ROLE_KEY);
}

function getClient() {
  if (client) return client;
  if (!isConfigured()) return null;
  const { createClient } = require('@supabase/supabase-js');
  client = createClient(process.env.SUPABASE_URL, process.env.SUPABASE_SERVICE_ROLE_KEY);
  return client;
}

/**
 * Returns all contact rows where owner matches userId (case-insensitive).
 * Ordered alphabetically by name.
 */
async function getContactsForOwner(userId) {
  const supabase = getClient();
  if (!supabase) throw new Error('Supabase not configured');
  const uid = userId ? String(userId).trim() : '';
  if (!uid) return [];

  const { data, error } = await supabase
    .from('contacts')
    .select('*')
    .ilike('owner', uid)
    .order('name', { ascending: true });
  if (error) throw error;
  return data || [];
}

async function insertContact({ name, owner, private_notes }) {
  const supabase = getClient();
  if (!supabase) throw new Error('Supabase not configured');
  const n = name != null ? String(name).trim() : '';
  const o = owner != null ? String(owner).trim() : '';
  if (!n) throw new Error('name is required');
  if (!o) throw new Error('owner is required');
  const row = { name: n, owner: o };
  if (private_notes !== undefined && private_notes != null && String(private_notes).trim() !== '') {
    row.private_notes = String(private_notes).trim();
  }
  const { data, error } = await supabase.from('contacts').insert(row).select('*').single();
  if (error) throw error;
  return data;
}

function normalizeEmail(s) {
  return s != null ? String(s).trim().toLowerCase() : '';
}

/**
 * True if a contact row exists for this owner with matching name (case-insensitive, trimmed).
 */
async function hasContactForOwner(ownerUserId, contactName) {
  const supabase = getClient();
  if (!supabase) throw new Error('Supabase not configured');
  const uid = normalizeEmail(ownerUserId);
  const want = String(contactName || '').trim().toLowerCase();
  if (!uid || !want) return false;

  const { data, error } = await supabase
    .from('contacts')
    .select('id, name')
    .ilike('owner', uid);
  if (error) throw error;
  return (data || []).some(
    r => String(r.name || '').trim().toLowerCase() === want
  );
}

/**
 * Deletes one contact by id if owner matches ownerUserId (case-insensitive).
 * Returns true if a row was deleted.
 */
async function deleteContactByIdForOwner(id, ownerUserId) {
  const supabase = getClient();
  if (!supabase) throw new Error('Supabase not configured');
  const uid = normalizeEmail(ownerUserId);
  const cid = id != null ? String(id).trim() : '';
  if (!uid || !cid) return false;

  const { data: row, error: selErr } = await supabase
    .from('contacts')
    .select('id, owner')
    .eq('id', cid)
    .maybeSingle();
  if (selErr) throw selErr;
  if (!row) return false;
  if (normalizeEmail(row.owner) !== uid) {
    throw Object.assign(new Error('Forbidden'), { status: 403 });
  }
  const { error } = await supabase.from('contacts').delete().eq('id', cid);
  if (error) throw error;
  return true;
}

/**
 * Deletes all contacts where owner matches (case-insensitive) and name matches (trim, case-insensitive).
 * Returns number of rows deleted.
 */
async function deleteContactsByOwnerAndName(ownerUserId, name) {
  const supabase = getClient();
  if (!supabase) throw new Error('Supabase not configured');
  const uid = normalizeEmail(ownerUserId);
  const want = String(name || '').trim().toLowerCase();
  if (!uid || !want) return 0;

  const { data: rows, error } = await supabase
    .from('contacts')
    .select('id, owner, name')
    .ilike('owner', uid);
  if (error) throw error;
  const toDelete = (rows || []).filter(
    r => normalizeEmail(r.owner) === uid && String(r.name || '').trim().toLowerCase() === want
  );
  if (!toDelete.length) return 0;
  const { error: delErr } = await supabase
    .from('contacts')
    .delete()
    .in(
      'id',
      toDelete.map(r => r.id)
    );
  if (delErr) throw delErr;
  return toDelete.length;
}

/**
 * Updates name and/or notes for a contact row. Verifies owner (case-insensitive).
 * `notes` maps to the `notes` column.
 */
async function updateContactForOwner({ id, ownerUserId, name, notes }) {
  const supabase = getClient();
  if (!supabase) throw new Error('Supabase not configured');
  const uid = normalizeEmail(ownerUserId);
  const cid = id != null ? String(id).trim() : '';
  if (!uid || !cid) throw new Error('id and owner are required');

  const { data: row, error: selErr } = await supabase
    .from('contacts')
    .select('id, owner')
    .eq('id', cid)
    .maybeSingle();
  if (selErr) throw selErr;
  if (!row) throw Object.assign(new Error('Contact not found'), { status: 404 });
  if (normalizeEmail(row.owner) !== uid) {
    throw Object.assign(new Error('Forbidden'), { status: 403 });
  }

  const patch = {};
  if (name !== undefined) {
    const n = String(name).trim();
    if (!n) throw new Error('name cannot be empty');
    patch.name = n;
  }
  if (notes !== undefined) {
    patch.notes =
      notes == null || String(notes).trim() === '' ? null : String(notes).trim();
  }
  if (!Object.keys(patch).length) return true;

  const { error } = await supabase.from('contacts').update(patch).eq('id', cid);
  if (error) throw error;
  return true;
}

module.exports = {
  isConfigured,
  getContactsForOwner,
  insertContact,
  deleteContactByIdForOwner,
  deleteContactsByOwnerAndName,
  updateContactForOwner,
  hasContactForOwner
};
